from pydantic import field_validator
from enum import Enum

class StatusEnum(str, Enum):
    PENDING = 'pending'
    COMPLETED = 'completed'
    FAILED = 'failed'

class AgentResponse(BaseModel):
    status: StatusEnum

    @field_validator('status', mode='before')
    @classmethod
    def coerce_status(cls, v):
        if isinstance(v, str):
            # Map common hallucinations to valid enums
            mapping = {'done': 'completed', 'error': 'failed', 'purple': 'failed'}
            return mapping.get(v.lower(), v)
        return v

response = client.with_structured_output(AgentResponse).do(messages)
